INSERT INTO `bai_viet_phong` VALUES (2,1,'PHÒNG NỘI TRÚ','phong-noi-tru','<p><b><strong class=\"font-bold\" style=\"white-space: pre-wrap;\">Viện Dưỡng Lão Xuân Hoa – Phòng Nội Trú An Tâm Như Ở Nhà</strong></b></p><p><span style=\"white-space: pre-wrap;\">Phòng nội trú tại Viện Dưỡng Lão Xuân Hoa được xây dựng với mục tiêu mang đến cho người cao tuổi một không gian sống an toàn, ấm áp và đầy sự quan tâm. Từng chi tiết trong phòng đều được thiết kế phù hợp với thể trạng và nhu cầu sinh hoạt của người lớn tuổi, giúp các cụ cảm nhận được sự thoải mái và yên tâm trong suốt thời gian lưu trú.</span></p><p><span style=\"display: block; margin: 10px 0px;\"><img src=\"https://duonglaoxuanhoa.net/api_quanlyduonglao/uploads/file-1766109399097-546418753.jpg\" alt=\"image\" style=\"max-width: 100%; height: auto; display: block; margin: 0px auto; border-radius: 4px;\"></span></p><p><span style=\"white-space: pre-wrap;\">Hệ thống phòng ở luôn đảm bảo thông thoáng, sạch sẽ, đầy đủ ánh sáng tự nhiên, trang bị giường chuyên dụng, tủ cá nhân, nhà vệ sinh khép kín và hệ thống gọi hỗ trợ khẩn cấp 24/7. Không gian được bố trí gọn gàng, hạn chế vật cản, giảm nguy cơ té ngã và tạo điều kiện thuận lợi cho việc di chuyển.</span></p><p><span style=\"white-space: pre-wrap;\">Bên cạnh cơ sở vật chất, Phòng nội trú Viện Dưỡng Lão Xuân Hoa còn chú trọng đến công tác chăm sóc sức khỏe toàn diện. Đội ngũ điều dưỡng, y bác sĩ theo dõi tình trạng sức khỏe hằng ngày, hỗ trợ dùng thuốc, dinh dưỡng và chăm sóc cá nhân. Các bữa ăn được xây dựng khoa học, phù hợp với từng thể trạng, đảm bảo đủ chất và dễ tiêu hóa.</span></p><p><span style=\"display: block; margin: 10px 0px;\"><img src=\"https://duonglaoxuanhoa.net/api_quanlyduonglao/uploads/file-1766109418921-704869750.jpg\" alt=\"image\" style=\"max-width: 100%; height: auto; display: block; margin: 0px auto; border-radius: 4px;\"></span></p><p><span style=\"white-space: pre-wrap;\">Ngoài thời gian nghỉ ngơi, người cao tuổi tại phòng nội trú còn được tham gia các hoạt động sinh hoạt, giao lưu nhẹ nhàng và phục hồi chức năng, giúp tinh thần luôn vui vẻ, lạc quan. Môi trường sống thân thiện, giàu tình cảm tại Xuân Hoa không chỉ là nơi chăm sóc sức khỏe mà còn là mái nhà thứ hai, nơi người cao tuổi được yêu thương, tôn trọng và sống những năm tháng tuổi già một cách an nhiên.</span></p>','https://duonglaoxuanhoa.net/api_quanlyduonglao/uploads/file-1766109580687-795215363.jpg',NULL,NULL,'Giới thiệu về phòng nội trú của viện dưỡng lão Xuân Hoa',NULL,NULL,9,'xuat_ban',NULL,0,NULL,1,'2025-12-19 09:00:06','2026-02-16 10:55:14'),(3,2,'PHÒNG BÁN NỘI TRÚ','phong-ban-noi-tru','<p><b><strong class=\"font-bold\" style=\"white-space: pre-wrap;\">Viện Dưỡng Lão Xuân Hoa – Phòng Nội Trú An Tâm Như Ở Nhà</strong></b></p><p><span style=\"white-space: pre-wrap;\">Phòng nội trú tại Viện Dưỡng Lão Xuân Hoa được xây dựng với mục tiêu mang đến cho người cao tuổi một không gian sống an toàn, ấm áp và đầy sự quan tâm. Từng chi tiết trong phòng đều được thiết kế phù hợp với thể trạng và nhu cầu sinh hoạt của người lớn tuổi, giúp các cụ cảm nhận được sự thoải mái và yên tâm trong suốt thời gian lưu trú.</span></p><p><span style=\"display: block; margin: 10px 0px;\"><img src=\"https://duonglaoxuanhoa.net/api_quanlyduonglao/uploads/file-1766109399097-546418753.jpg\" alt=\"image\" style=\"max-width: 100%; height: auto; display: block; margin: 0px auto; border-radius: 4px;\"></span></p><p><span style=\"white-space: pre-wrap;\">Hệ thống phòng ở luôn đảm bảo thông thoáng, sạch sẽ, đầy đủ ánh sáng tự nhiên, trang bị giường chuyên dụng, tủ cá nhân, nhà vệ sinh khép kín và hệ thống gọi hỗ trợ khẩn cấp 24/7. Không gian được bố trí gọn gàng, hạn chế vật cản, giảm nguy cơ té ngã và tạo điều kiện thuận lợi cho việc di chuyển.</span></p><p><span style=\"white-space: pre-wrap;\">Bên cạnh cơ sở vật chất, Phòng nội trú Viện Dưỡng Lão Xuân Hoa còn chú trọng đến công tác chăm sóc sức khỏe toàn diện. Đội ngũ điều dưỡng, y bác sĩ theo dõi tình trạng sức khỏe hằng ngày, hỗ trợ dùng thuốc, dinh dưỡng và chăm sóc cá nhân. Các bữa ăn được xây dựng khoa học, phù hợp với từng thể trạng, đảm bảo đủ chất và dễ tiêu hóa.</span></p><p><span style=\"display: block; margin: 10px 0px;\"><img src=\"https://duonglaoxuanhoa.net/api_quanlyduonglao/uploads/file-1766109418921-704869750.jpg\" alt=\"image\" style=\"max-width: 100%; height: auto; display: block; margin: 0px auto; border-radius: 4px;\"></span></p><p><span style=\"white-space: pre-wrap;\">Ngoài thời gian nghỉ ngơi, người cao tuổi tại phòng nội trú còn được tham gia các hoạt động sinh hoạt, giao lưu nhẹ nhàng và phục hồi chức năng, giúp tinh thần luôn vui vẻ, lạc quan. Môi trường sống thân thiện, giàu tình cảm tại Xuân Hoa không chỉ là nơi chăm sóc sức khỏe mà còn là mái nhà thứ hai, nơi người cao tuổi được yêu thương, tôn trọng và sống những năm tháng tuổi già một cách an nhiên.</span></p>','https://duonglaoxuanhoa.net/api_quanlyduonglao/uploads/file-1766109652046-536980386.jpg',NULL,NULL,'Giới thiệu về phòng bán nội trú của viện dưỡng lão Xuân Hoa',NULL,NULL,28,'xuat_ban',NULL,0,NULL,1,'2025-12-19 09:00:53','2026-03-12 09:44:41');
