--
-- Table structure for table `duong_huyet`
--

DROP TABLE IF EXISTS `duong_huyet`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `duong_huyet` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `id_benh_nhan` bigint DEFAULT NULL,
  `gia_tri_duong_huyet` decimal(5,2) DEFAULT NULL COMMENT 'Giá trị đường huyết (mmol/L)',
  `thoi_gian_do` datetime DEFAULT NULL COMMENT 'Thời gian đo đường huyết',
  `thoi_diem_do` enum('sang','trua','toi','truoc_an','sau_an','truoc_ngu','khac') CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT 'Thời điểm đo đường huyết',
  `vi_tri_lay_mau` enum('ngon_tay','canh_tay','dui') CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT 'Vị trí lấy mẫu',
  `trieu_chung_kem_theo` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT 'Triệu chứng kèm theo (nếu có)',
  `ghi_chu` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci,
  `muc_do` enum('binh_thuong','canh_bao','nguy_hiem') CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT 'Mức độ cảnh báo',
  `noi_dung_canh_bao` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT 'Nội dung cảnh báo nếu có',
  `id_cau_hinh_chi_so_canh_bao` bigint DEFAULT NULL COMMENT 'ID cấu hình chỉ số cảnh báo',
  `danh_gia_chi_tiet` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT 'Đánh giá chi tiết (tự động tính)',
  `ngay_tao` datetime DEFAULT CURRENT_TIMESTAMP,
  `ngay_cap_nhat` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `id_benh_nhan` (`id_benh_nhan`),
  KEY `idx_duong_huyet_thoi_gian_do` (`thoi_gian_do`),
  KEY `fk_duong_huyet_cau_hinh` (`id_cau_hinh_chi_so_canh_bao`),
  CONSTRAINT `duong_huyet_ibfk_1` FOREIGN KEY (`id_benh_nhan`) REFERENCES `benh_nhan` (`id`) ON DELETE CASCADE,
  CONSTRAINT `fk_duong_huyet_cau_hinh` FOREIGN KEY (`id_cau_hinh_chi_so_canh_bao`) REFERENCES `cau_hinh_chi_so_canh_bao` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=158 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;
