INSERT INTO `duong_huyet` VALUES (4,19,16.00,'2025-12-22 09:29:00',NULL,NULL,NULL,NULL,'nguy_hiem','Đường huyết rất cao (>11.0 mmol/L) hoặc rất thấp (<4.0 mmol/L)! Nguy cơ hôn mê tăng đường huyết (DKA, HHS) hoặc hôn mê hạ đường huyết. Cần can thiệp ngay: kiểm tra ketone, điện giải, có thể cần insulin hoặc glucose tĩnh mạch.',24,'nguy_hiem','2025-12-22 09:29:35','2025-12-22 09:29:35'),(5,19,10.00,'2025-12-22 21:40:00',NULL,'ngon_tay','dsdfsd','23234r4','canh_bao','Hạ đường huyết (<4.0 mmol/L). Kiểm tra triệu chứng: run, vã mồ hôi, lú lẫn, hôn mê. Xử trí ngay: uống/bơm glucose, kiểm tra lại sau 15 phút. Điều chỉnh thuốc nếu tái phát.',24,'thap','2025-12-23 04:35:36','2025-12-23 04:36:02'),(6,18,3.50,'2025-12-24 16:21:00',NULL,'canh_tay',NULL,NULL,'canh_bao','Hạ đường huyết (<4.0 mmol/L). Kiểm tra triệu chứng: run, vã mồ hôi, lú lẫn, hôn mê. Xử trí ngay: uống/bơm glucose, kiểm tra lại sau 15 phút. Điều chỉnh thuốc nếu tái phát.',24,'thap','2025-12-24 09:21:34','2025-12-24 09:21:34'),(7,18,5.00,'2025-12-24 16:21:00',NULL,'canh_tay',NULL,NULL,'binh_thuong','Đường huyết trong giới hạn bình thường (4.0-7.0 mmol/L).',24,'binh_thuong','2025-12-24 09:21:46','2025-12-24 09:21:46'),(8,18,8.00,'2025-12-24 16:22:00',NULL,'canh_tay',NULL,NULL,'canh_bao','Tăng đường huyết (7.1-11.0 mmol/L). Đánh giá lại chế độ ăn, thuốc điều trị đái tháo đường, hoạt động thể chất. Điều chỉnh điều trị nếu cần.',24,'cao','2025-12-24 09:22:03','2025-12-24 09:22:03'),(9,22,18.00,'2026-01-05 17:09:00','trua','canh_tay','hô','hahaj','nguy_hiem',NULL,NULL,'Hạ đường huyết','2026-01-05 10:09:33','2026-01-05 10:09:33'),(10,22,18.00,'2026-01-05 17:10:17','toi','dui','h4','jjj\n','nguy_hiem',NULL,NULL,'Hạ đường huyết','2026-01-05 10:10:17','2026-01-05 10:10:17'),(11,22,19.00,'2026-01-05 17:10:00','toi','dui','h4','jjj\n','nguy_hiem',NULL,NULL,'Hạ đường huyết','2026-01-05 10:10:26','2026-01-05 10:10:26'),(12,22,20.00,'2026-01-05 17:10:00','toi','dui','h4','jjj\n','nguy_hiem',NULL,NULL,'Hạ đường huyết','2026-01-