--
-- Table structure for table `fcm_tokens`
--

DROP TABLE IF EXISTS `fcm_tokens`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `fcm_tokens` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `tai_khoan_id` bigint NOT NULL COMMENT 'ID tài khoản từ bảng tai_khoan',
  `token` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT 'FCM token từ Firebase',
  `device_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT 'android' COMMENT 'Loại thiết bị: android, ios',
  `app_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT 'Loại app: nurse_app, family_app',
  `is_active` tinyint(1) DEFAULT '1' COMMENT 'Token còn hoạt động: 1=active, 0=inactive',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP COMMENT 'Thời gian tạo',
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT 'Thời gian cập nhật',
  PRIMARY KEY (`id`),
  UNIQUE KEY `unique_tai_khoan_token` (`tai_khoan_id`,`token`),
  KEY `idx_tai_khoan_id` (`tai_khoan_id`),
  KEY `idx_token` (`token`),
  KEY `idx_is_active` (`is_active`),
  KEY `idx_app_type` (`app_type`),
  KEY `idx_user_active_tokens` (`tai_khoan_id`,`is_active`),
  KEY `idx_app_type_active` (`app_type`,`is_active`),
  CONSTRAINT `fk_fcm_tokens_tai_khoan` FOREIGN KEY (`tai_khoan_id`) REFERENCES `tai_khoan` (`id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=147 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='Bảng lưu FCM tokens cho push notifications';
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `fcm_tokens`
--

