/*!40000 ALTER TABLE `loai_dich_vu` DISABLE KEYS */;
INSERT INTO `loai_dich_vu` VALUES (1,'Chăm sóc nội trú','Dịch vụ chăm sóc nội trú mang đến không gian sống ổn định và an toàn cho người cao tuổi với sự hỗ trợ 24/7 từ đội ngũ nhân viên chuyên nghiệp. Người cao tuổi được chăm sóc toàn diện từ sinh hoạt cá nhân, ăn uống, nghỉ ngơi đến theo dõi và quản lý sức khỏe lâu dài. Không chỉ đáp ứng nhu cầu thể chất, chăm sóc nội trú còn chú trọng đời sống tinh thần thông qua các hoạt động giao lưu, sinh hoạt chung, tạo cảm giác ấm cúng, gần gũi và giúp người cao tuổi an tâm tận hưởng cuộc sống tuổi già.','2025-12-19 09:07:53','2025-12-19 09:10:09'),(2,'Chăm sóc ban ngày','Chăm sóc ban ngày là dịch vụ phù hợp với những gia đình mong muốn người cao tuổi được chăm sóc chuyên nghiệp trong giờ hành chính nhưng vẫn sinh hoạt tại nhà vào buổi tối. Trong thời gian ban ngày, người cao tuổi được theo dõi sức khỏe, hỗ trợ ăn uống, nghỉ ngơi và tham gia các hoạt động sinh hoạt chung, giao lưu tinh thần hoặc rèn luyện nhẹ nhàng. Môi trường thân thiện, an toàn giúp các cụ luôn vui vẻ, giảm cảm giác cô đơn, đồng thời gia đình có thể yên tâm công tác và sinh hoạt.','2025-12-19 09:08:04','2025-12-19 09:09:43'),(3,'Vật lý trị liệu','Dịch vụ vật lý trị liệu được thiết kế phù hợp với từng tình trạng sức khỏe và khả năng vận động của người cao tuổi. Thông qua các bài tập phục hồi chức năng, xoa bóp, vận động trị liệu và các phương pháp hỗ trợ khác, dịch vụ giúp cải thiện khả năng đi lại, giảm đau nhức xương khớp và tăng cường sự linh hoạt của cơ thể. Quá trình trị liệu được theo dõi sát sao bởi đội ngũ chuyên môn, góp phần nâng cao thể lực, hạn chế biến chứng và giúp người cao tuổi tự tin hơn trong sinh hoạt hằng ngày.','2025-12-19 09:08:12','2025-12-19 09:09:33'),(4,'Chăm sóc y tế','Dịch vụ chăm sóc y tế tại viện dưỡng lão được xây dựng nhằm đảm bảo sức khỏe toàn diện cho người cao tuổi trong suốt quá trình sinh hoạt và nghỉ ngơi. Người cao tuổi được thăm khám định kỳ, theo dõi các chỉ số sức khỏe, hỗ trợ dùng thuốc đúng giờ, đúng liều theo chỉ định của bác sĩ. Đội ngũ y bác sĩ và điều dưỡng luôn túc trực, sẵn sàng xử lý kịp thời các tình huống phát sinh, đồng thời tư vấn sức khỏe, phòng ngừa bệnh tật, giúp người cao tuổi an tâm và duy trì cuộc sống ổn định, chất lượng.','2025-12-19 09:08:19','2025-12-19 09:09:22');
/*!40000 ALTER TABLE `loai_dich_vu` ENABLE KEYS */;
UNLOCK TABLES;

