INSERT INTO `loai_phong` VALUES (1,'PHÒNG NỘI TRÚ','Phòng nội trú của viện dưỡng lão được thiết kế ấm cúng, yên tĩnh và an toàn, mang lại cảm giác như ở nhà cho người cao tuổi. Không gian phòng thoáng đãng, đầy đủ ánh sáng tự nhiên, trang bị giường chuyên dụng, hệ thống gọi hỗ trợ khẩn cấp và các tiện nghi cần thiết cho sinh hoạt hằng ngày. Mỗi phòng đều được vệ sinh, chăm sóc định kỳ, đảm bảo sự thoải mái và riêng tư, giúp người cao tuổi an tâm nghỉ ngơi và phục hồi sức khỏe trong môi trường thân thiện, giàu sự quan tâm.','http://localhost:4545/uploads/file-1766050011068-207700875.jpg','2025-12-18 15:58:37','2025-12-19 08:47:28'),(2,'PHÒNG BÁN NỘI TRÚ','Phòng bán nội trú của viện dưỡng lão là không gian sinh hoạt ban ngày dành cho người cao tuổi, được bố trí tiện nghi, sạch sẽ và an toàn. Phòng được trang bị khu nghỉ ngơi, bàn ghế sinh hoạt chung, điều hòa, ánh sáng tự nhiên cùng các thiết bị hỗ trợ cần thiết. Tại đây, người cao tuổi được chăm sóc, theo dõi sức khỏe, tham gia các hoạt động giao lưu – phục hồi chức năng trong ngày và trở về nhà vào buổi tối, mang lại sự linh hoạt và cảm giác gần gũi cho gia đình.','http://localhost:4545/uploads/file-1766109027570-359368439.jpg','2025-12-19 08:52:40','2025-12-19 08:52:40');
/*!40000 ALTER TABLE `loai_phong` ENABLE KEYS */;
UNLOCK TABLES;

