--
-- Table structure for table `nhiet_do`
--

DROP TABLE IF EXISTS `nhiet_do`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `nhiet_do` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `id_benh_nhan` bigint DEFAULT NULL,
  `gia_tri_nhiet_do` decimal(4,2) DEFAULT NULL COMMENT 'Giá trị nhiệt độ (°C)',
  `thoi_gian_do` datetime DEFAULT NULL COMMENT 'Thời gian đo nhiệt độ',
  `vi_tri_do` enum('tran','tai','mieng','nach','truc_trang') CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT 'Vị trí đo',
  `tinh_trang_luc_do` enum('nghi_ngoi','van_dong','sau_an','sau_ngu') CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT 'Tình trạng lúc đo',
  `ghi_chu` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci,
  `muc_do` enum('binh_thuong','canh_bao','nguy_hiem') CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT 'Mức độ cảnh báo',
  `noi_dung_canh_bao` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT 'Nội dung cảnh báo nếu có',
  `id_cau_hinh_chi_so_canh_bao` bigint DEFAULT NULL COMMENT 'ID cấu hình chỉ số cảnh báo',
  `danh_gia_chi_tiet` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci COMMENT 'Đánh giá chi tiết (tự động tính)',
  `ngay_tao` datetime DEFAULT CURRENT_TIMESTAMP,
  `ngay_cap_nhat` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `id_benh_nhan` (`id_benh_nhan`),
  KEY `idx_nhiet_do_thoi_gian_do` (`thoi_gian_do`),
  KEY `fk_nhiet_do_cau_hinh` (`id_cau_hinh_chi_so_canh_bao`),
  CONSTRAINT `fk_nhiet_do_cau_hinh` FOREIGN KEY (`id_cau_hinh_chi_so_canh_bao`) REFERENCES `cau_hinh_chi_so_canh_bao` (`id`) ON DELETE SET NULL,
  CONSTRAINT `nhiet_do_ibfk_1` FOREIGN KEY (`id_benh_nhan`) REFERENCES `benh_nhan` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=179 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `nhiet_do`
--

LOCK TABLES `nhiet_do` WRITE;
/*!40000 ALTER TABLE `nhiet_do` DISABLE KEYS */;
INSERT INTO `nhiet_do` VALUES (5,18,35.00,'2025-12-24 16:22:00',NULL,NULL,NULL,'nguy_hiem','Sốt cao (>38.5°C) hoặc hạ thân nhiệt nghiêm trọng (<36.5°C)! Nguy cơ co giật, tổn thương não, nhiễm trùng huyết. Cần hạ sốt ngay (paracetamol, lau mát), đánh giá nguyên nhân, có thể cần kháng sinh hoặc điều trị hỗ trợ.',26,'nguy_hiem','2025-12-24 09:22:21','2025-12-24 09:22:32'),(6,18,35.00,'2025-12-24 16:22:00',NULL,NULL,NULL,'canh_bao','Hạ thân nhiệt (<36.5°C). Giữ ấm, theo dõi, đánh giá nguyên nhân (nhiễm trùng nặng ở người già, suy giáp, thuốc).',26,'thap','2025-12-24 09:22:40','2025-12-24 09:22:40'),(7,22,38.60,'2026-01-04 14:38:00','tai','nghi_ngoi','dr','canh_bao','Sốt vừa - Cần theo dõi',NULL,'sot_vua','2026-01-05 09:38:39','2026-01-05 09:38:39'),(8,22,38.60,'2026-01-05 16:39:53','tai','nghi_ngoi','dr','canh_bao','Sốt vừa - Cần theo dõi',NULL,'sot_vua','2026-01-05 09:39:53','2026-01-05 09:39:53'),(10,22,39.00,'2026-01-05 16:40:00','tran','sau_an','g','canh_bao','Sốt cao - Cần theo dõi chặt chẽ',NULL,'sot_cao','2026-01-05 09:40:53','2026-01-05 09:40:53'),(11,22,39.20,'2026-01-06 11:49:00','tran','sau_an','g','canh_bao','Sốt cao - Cần theo dõi chặt chẽ',NULL,'sot_cao','2026-01-06 04:49:35','2026-01-06 04:49:35'),(12,21,36.00,'2026-01-07 09:53:00','tran','nghi_ngoi','hihihi','binh_thuong',NULL,NULL,'binh_thuong','2026-01-07 02:54:03','2026-01-07 02:54:03'),(13,21,37.00,'2026-01-08 10:28:00','tran','nghi_ngoi','hihihi','binh_thuong',NULL,NULL,'binh_thuong','2026-01-08 03:28:30','2026-01-08 03:28:30'),(14,22,37.00,'2026-01-08 14:36:00','tran','sau_an','g','binh_thuong',NULL,NULL,'binh_thuong','2026-01-08 07:36:36','2026-01-08 07:36:36'),(15,22,35.90,'2026-01-05 14:25:00','tai','van_dong','gà','binh_thuong',NULL,NULL,'binh_thuong','2026-01-08 08:21:23','2026-01-08 08:21:23'),(16,22,37.90,'2026-01-05 11:45:00','tai','van_dong','gà','binh_thuong','Sốt nhẹ',NULL,'sot_nhe','2026-01-08 08:21:48','2026-01-08 08:21:48'),(17,22,36.00,'2026-01-08 15:23:00','tran','sau_an','g','binh_