INSERT INTO `su_kien` VALUES (2,'Lễ hội Giáng Sinh','Lễ hội Giáng Sinh là sự kiện thường niên được tổ chức tại viện dưỡng lão nhằm mang đến không khí ấm áp, vui tươi và gắn kết cho người cao tuổi trong mùa lễ cuối năm. Chương trình được trang trí rực rỡ với cây thông Noel, ánh đèn lung linh và không gian thân thiện, tạo cảm giác gần gũi như trong gia đình.\nTrong khuôn khổ lễ hội, người cao tuổi được tham gia các hoạt động ý nghĩa như giao lưu, ca hát các bài nhạc Giáng Sinh quen thuộc, thưởng thức tiệc nhẹ, nhận quà và cùng nhau chia sẻ những khoảnh khắc ấm áp. Đây không chỉ là dịp mang lại niềm vui tinh thần mà còn giúp các cụ cảm nhận được sự quan tâm, yêu thương từ đội ngũ nhân viên, gia đình và cộng đồng.\nLễ hội Giáng Sinh tại viện dưỡng lão không chỉ đơn thuần là một sự kiện giải trí, mà còn là hoạt động chăm sóc tinh thần quan trọng, góp phần lan tỏa niềm vui, sự an yên và hạnh phúc cho người cao tuổi trong không khí sum vầy, ấm áp của mùa lễ hội.','2026-01-05 04:31:00','Viện Dưỡng lão Xuân Hoa','sinh_hoat',1000000,'https://duonglaoxuanhoa.net/api_quanlyduonglao/uploads/file-1766118713423-527353096.jpg',NULL,'ket_thuc',0,NULL,'2025-12-19 11:32:33','2026-02-28 02:02:59'),(3,'Năm mới  happpy','Chúc mừng năm mới haha ','2025-12-31 11:00:00','Hà Nội 2','sinh_hoat',11111,'https://duonglaoxuanhoa.net/api_quanlyduonglao/uploads/file-1766477380015-162004248.jpg',NULL,'sap_dien_ra',1,'2025-12-23 08:10:35','2025-12-23 08:07:57','2025-12-29 09:02:57'),(4,'Lễ Hội Mùa ODodng',NULL,'2026-01-09 15:27:00','Hà Nội','sinh_hoat',NULL,NULL,NULL,'ket_thuc',0,NULL,'2025-12-24 07:27:20','2026-02-28 02:02:59'),(5,'Đi chùa','Đi chùa','2026-01-06 14:56:00','Bắc Ninh','sinh_hoat',50000000,NULL,NULL,'ket_thuc',0,NULL,'2026-01-05 07:56:40','2026-02-28 02:02:59'),(6,'Bắt nạt đồng nghiệp cũ',NULL,'2026-01-10 16:35:00','Viện Tin học Xây Dựng','sinh_hoat',NULL,NULL,NULL,'ket_thuc',0,NULL,'2026-01-09 02:27:22','2026-02-28 02:02:59'),(7,'Thứ 7',NULL,'2026-01-10 17:10:00',NULL,'sinh_hoat',NULL