DROP TABLE IF EXISTS `tai_khoan`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `tai_khoan` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `ho_ten` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL,
  `so_dien_thoai` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL,
  `email` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL,
  `avatar` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci,
  `mat_khau` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci,
  `vai_tro` enum('super_admin','quan_ly_y_te','quan_ly_nhan_su','dieu_duong','dieu_duong_truong','nguoi_nha','marketing') CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL,
  `trang_thai` enum('active','inactive','locked') CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT 'active',
  `da_xoa` tinyint(1) DEFAULT '0',
  `ngay_xoa` datetime DEFAULT NULL,
  `ngay_tao` datetime DEFAULT CURRENT_TIMESTAMP,
  `ngay_cap_nhat` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `idx_tai_khoan_vai_tro` (`vai_tro`),
  KEY `idx_so_dien_thoai` (`so_dien_thoai`),
  KEY `idx_email` (`email`),
  KEY `idx_so_dien_thoai_vai_tro_da_xoa` (`so_dien_thoai`,`vai_tro`,`da_xoa`),
  KEY `idx_email_vai_tro_da_xoa` (`email`,`vai_tro`,`da_xoa`)
) ENGINE=InnoDB AUTO_INCREMENT=81 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;
