INSERT INTO `tin_tuyen_dung` VALUES (2,'Tuyển dụng vị trí Bác Sĩ Chuyên Khoa tháng 12/2025','Viện Dưỡng lão Xuân Hoa cần tuyển bác sĩ chuyên khoa đảm nhận vị trí tại khoa Lão Khoa.','Bác sĩ chuyên khoa','- Tốt nghiệp Đại học tại ngành Y và các chuyên ngành liên quan\n- Có ít nhất 5 năm kinh nghiệm tại vị trí bác sĩ chuyên khoa\n- Chịu đựng được cường độ làm việc cao, liên tục\n- Làm việc từ thứ 2 đến thứ 6\n- Có ít nhất 3 năm kinh nghiệm phẫu thuật\n- Học vị từ PGS ( nice to have)',1,'2025-12-18 15:07:12','2025-12-27 08:07:00','dang_tuyen','2025-12-18 15:07:12','2025-12-18 15:08:08'),(3,'Bác sĩ nội trú A','Làm việc nội trú A','Bác sĩ A','Đại học A',6,'2025-12-23 08:30:52','2025-12-26 06:34:00','dang_tuyen','2025-12-23 08:30:52','2025-12-23 08:31:52'),(4,'Bác sĩ đa khoa','Hoho','Kế toán','2+',2,'2026-01-20 02:19:15','2026-01-24 12:19:00','dang_tuyen','2026-01-20 02:19:15','2026-01-20 02:19:15');
